mapper.select:
select count(0)
from sas
where user_id=#{userId} and log_date=#{date}

mapper.update:
update sas
set sas_q1=#{sasQ1},sas_q2=#{sasQ2},sas_q3=#{sasQ3},sas_q4=#{sasQ4},sas_q5=#{sasQ5},sas_q6=#{sasQ6},
    sas_q7=#{sasQ7},sas_q8=#{sasQ8},sas_q9=#{sasQ9},sas_q10=#{sasQ10},sas_q11=#{sasQ11},sas_q12=#{sasQ12},
    sas_q13=#{sasQ13},sas_q13=#{sasQ13},sas_q14=#{sasQ14},sas_q15=#{sasQ15},sas_q16=#{sasQ16},sas_q17=#{sasQ17},
    sas_q18=#{sasQ18},sas_q19=#{sasQ19},sas_q20=#{sasQ20},score=#{score}
where user_id = #{userId} and log_date=#{logDate}
